from flask import Flask, request, send_file, abort
import os

app = Flask(__name__)

# Mock database of invoices
invoices_db = {
    1: {'id': 1, 'file_path': 'path/to/invoice_1.pdf', 'user_id': 101},
    2: {'id': 2, 'file_path': 'path/to/invoice_2.pdf', 'user_id': 102}
}

# Mock user roles
user_roles = {
    101: 'admin',
    102: 'user'
}

def check_authorization(invoice_id, user_id):
    if invoice_id not in invoices_db:
        abort(404)
    
    invoice = invoices_db[invoice_id]
    if invoice['user_id'] != user_id and user_roles.get(user_id) != 'admin':
        abort(403)

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    user_id = request.args.get('user_id')
    
    if not user_id:
        return "User ID is required", 400
    
    check_authorization(invoice_id, int(user_id))
    
    invoice = invoices_db[invoice_id]
    file_path = invoice['file_path']
    
    if os.path.exists(file_path):
        return send_file(file_path, as_attachment=True)
    else:
        abort(404)

